@pytest.mark.asyncio
async def test_map_discover_urls() -> None:
    """Discovers all URLs on a site without fetching full content."""
    engine_config = CrawlConfig(max_depth=0, respect_robots_txt=False)
    engine = create_engine(engine_config)
    url = (
        os.environ.get("MOCK_SERVER_MAP_DISCOVER_URLS")
        or os.environ["MOCK_SERVER_URL"] + "/fixtures/map_discover_urls"
    )

    result = await map_urls(engine, url)
    assert len(result.urls) >= 3  # noqa: S101


